private void xrTableCell6_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal Deads = 0;
    decimal Culls= 0;
    decimal SettedEggsGradeOut = 0;
    decimal result = 0;
    if (GetCurrentColumnValue("Deads") != null )
        Deads = Convert.ToDecimal(GetCurrentColumnValue("Deads"));

    if (GetCurrentColumnValue("Culls") != null)
        Culls= Convert.ToDecimal(GetCurrentColumnValue("Culls"));

    if (GetCurrentColumnValue("SettedEggs") != null)
        SettedEggsGradeOut = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));


    if (SettedEggsGradeOut != 0)
    result = ((Deads  + Culls) *100)/ SettedEggsGradeOut ;

    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("N2"); 
    DeadsReport += Deads ;
    CullsReport += Culls;
    SettedEggsGradeOutReport += SettedEggsGradeOut ;
    GradeOutReport = DeadsReport  + CullsReport ;

}


private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      decimal Deads = 0;
    decimal Culls= 0;
    decimal SettedEggsGradeOut = 0;
    if (GetCurrentColumnValue("Deads") != null )
        Deads = Convert.ToDecimal(GetCurrentColumnValue("Deads"));

    if (GetCurrentColumnValue("Culls") != null)
        Culls= Convert.ToDecimal(GetCurrentColumnValue("Culls"));

    if (GetCurrentColumnValue("SettedEggs") != null)
        SettedEggsGradeOut = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    DeadsGroup += Deads ;
    CullsGroup += Culls;
    SettedEggsGradeOutGroup += SettedEggsGradeOut ;
    GradeOutGroup = DeadsGroup + CullsGroup ;

    //new lgoc for breeder
    decimal FChicks = 0;
    decimal MChicks = 0;
    decimal SettedEggs_Breeder = 0;

    // --- FChicks ---
    if (GetCurrentColumnValue("FChicks") != null)
        FChicks = Convert.ToDecimal(GetCurrentColumnValue("FChicks"));

    // --- MChicks ---
    if (GetCurrentColumnValue("MChicks") != null)
        MChicks = Convert.ToDecimal(GetCurrentColumnValue("MChicks"));

    // --- SettedEggs ---
    if (GetCurrentColumnValue("SettedEggs") != null)
        SettedEggs_Breeder = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));


    FChicksGroup += FChicks ;
    MChicksGroup += MChicks ;
    SettedEggsBreederGroup += SettedEggs_Breeder ;
    BreederGroup = FChicksGroup + MChicksGroup ;

    //new logic for broiler
    decimal Chicks = 0;
    decimal SettedEggsChicks = 0;

    // --- Chicks ---
    if (GetCurrentColumnValue("Chicks") != null)
        Chicks = Convert.ToDecimal(GetCurrentColumnValue("Chicks"));

    // --- SettedEggs ---
    if (GetCurrentColumnValue("SettedEggs") != null)
        SettedEggsChicks = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    ChicksGroup += Chicks ;
    SettedEggsChicksGroup += SettedEggsChicks  ;


    //new logic for Total Chicks
    decimal SettedEggsTotalChicks = 0;
    decimal UnHatEggs = 0;
    decimal DestroyEggs = 0;
    decimal NonHatched = 0;
    decimal TotalChicks = 0;

    // --- SettedEggs ---
    if (GetCurrentColumnValue("SettedEggs") != null)
       SettedEggsTotalChicks  = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    // --- UnHatEggs ---
    if (GetCurrentColumnValue("UnHatEggs") != null)
        UnHatEggs = Convert.ToDecimal(GetCurrentColumnValue("UnHatEggs"));

    // --- DestroyEggs ---
    if (GetCurrentColumnValue("DestroyEggs") != null)
        DestroyEggs = Convert.ToDecimal(GetCurrentColumnValue("DestroyEggs"));

    // --- @NonHatched = UnHatEggs + DestroyEggs ---
    NonHatched = UnHatEggs + DestroyEggs;

    // --- @TotalChicks = SettedEggs - NonHatched ---
    TotalChicks = SettedEggsTotalChicks  - NonHatched;
    TotalChicksGroup += TotalChicks;
    SettedEggstotalChicksGroup += SettedEggsTotalChicks  ;


}

