private void tdCredit_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
decimal FChicks = 0;
decimal MChicks = 0;
decimal SettedEggs = 0;
decimal result = 0;

// --- FChicks ---
if (GetCurrentColumnValue("FChicks") != null)
    FChicks = Convert.ToDecimal(GetCurrentColumnValue("FChicks"));

// --- MChicks ---
if (GetCurrentColumnValue("MChicks") != null)
    MChicks = Convert.ToDecimal(GetCurrentColumnValue("MChicks"));

// --- SettedEggs ---
if (GetCurrentColumnValue("SettedEggs") != null)
    SettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

// --- Breeders = FChicks + MChicks ---
decimal Breeders = FChicks + MChicks;

// --- Calculate result ---
if (SettedEggs != 0)
    result = (Breeders * 100) / SettedEggs;

// --- Write result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N2");

// If you need accumulators (same style as your previous code)
FChicksReport += FChicks ;
MChicksReport += MChicks ;
BreederTotal = FChicksReport  + MChicksReport ;
SettedEggsBreederReport += SettedEggs;

}

