private void xrTableCell15_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
decimal Chicks = 0;
decimal SettedEggs = 0;
decimal result = 0;

// --- Chicks ---
if (GetCurrentColumnValue("Chicks") != null)
    Chicks = Convert.ToDecimal(GetCurrentColumnValue("Chicks"));

// --- SettedEggs ---
if (GetCurrentColumnValue("SettedEggs") != null)
    SettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

// --- Calculate Percentage ---
if (SettedEggs != 0)
    result = (Chicks * 100m) / SettedEggs;

// --- Write to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N2");

// --- Accumulators (Group or Report totals) ---
ChicksReport += Chicks;
SettedEggsChicksReport += SettedEggs;
}



